module adder_pipe_64bit
(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [64:0] result,
    output o_en
);

    // Register to store the input enable signal.
    reg i_en_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            i_en_reg <= 0;
        end else begin
            i_en_reg <= i_en;
        end
    end
    // Register to store the input operand A.
    reg [63:0] adda_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            adda_reg <= 0;
        end else begin
            adda_reg <= adda;
        end
    end
    // Register to store the input operand B.
    reg [63:0] addb_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            addb_reg <= 0;
        end else begin
            addb_reg <= addb;
        end
    end
    // Register to store the output enable signal.
    reg o_en_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            o_en_reg <= 0;
        end else begin
            o_en_reg <= i_en_reg;
        end
    end
    // Register to store the carry value.
    reg carry;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            carry <= 0;
        end else begin
            carry <= i_en_reg ? sum[63] : carry;
        end
    end
    // Register to store the sum value.
    reg [63:0] sum;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum <= 0;
        end else begin
            sum <= i_en_reg ? sum[63:0] : sum;
        end
    end
    // Pipeline stage logic to calculate the sum and carry values based on the input operands and carry from the previous stage.
    wire [64:0] sum_temp;
    assign sum_temp[0] = adda_reg[0] ^ addb_reg[0] ^ carry;
    assign carry = (adda_reg[0] & addb_reg[0]) | (adda_reg[0] & carry) | (addb_reg[0] & carry);
    genvar i;
    generate
        for (i = 1; i < 64; i = i + 1) begin : pipeline_stage
            assign sum_temp[i] = adda_reg[i] ^ addb_reg[i] ^ carry;
            assign carry = (adda_reg[i] & addb_reg[i]) | (adda_reg[i] & carry) | (addb_reg[i] & carry);
        end
    endgenerate
    assign sum_temp[64] = carry;
    // Assign the output ports based on the registers.
    assign result = sum_temp;
    assign o_en = o_en_reg;
endmodule
